class Solution {
public:
    int minimizedStringLength(string s) {
        int count[26] = {0};
        for (char c : s) {
            count[c - 'a']++;
        }
        int ans = 0;
        for (int i = 0; i < 26; i++) {
            if (count[i] > 0) {
                ans += (count[i] % 2);
            }
        }
        return max(ans, 1);
    }
};
